1	import { describe, it, expect, beforeAll } from "vitest";
2	import {
3	  getOutcomeColor,
4	  scaleNumber,
5	  buildLinePath,
6	  formatTimestampLabel,
7	  formatBucketRangeLabel,
8	  formatSignedCurrency,
9	} from "@/features/analytics/chartUtils";
10	
11	beforeAll(() => {
12	  process.env.TZ = "UTC";
13	});
14	
15	describe("getOutcomeColor", () => {
16	  it("returns first color for index 0", () => expect(getOutcomeColor(0)).toBe("#818cf8"));
17	  it("returns second color for index 1", () => expect(getOutcomeColor(1)).toBe("#22c55e"));
18	  it("wraps around after 6 colors", () => expect(getOutcomeColor(6)).toBe("#818cf8"));
19	  it("wraps correctly for index 7", () => expect(getOutcomeColor(7)).toBe("#22c55e"));
20	  it("returns fallback for NaN index", () => expect(getOutcomeColor(NaN)).toBe("#818cf8"));
21	  it("returns fallback for negative index", () => expect(getOutcomeColor(-1)).toBe("#818cf8"));
22	});
23	
24	describe("scaleNumber", () => {
25	  it("maps domain midpoint to range midpoint", () => {
26	    expect(scaleNumber(50, 0, 100, 0, 200)).toBe(100);
27	  });
28	  it("maps domain min to range min", () => {
29	    expect(scaleNumber(0, 0, 100, 10, 20)).toBe(10);
30	  });
31	  it("maps domain max to range max", () => {
32	    expect(scaleNumber(100, 0, 100, 10, 20)).toBe(20);
33	  });
34	  it("returns range midpoint when domain is zero-width", () => {
35	    expect(scaleNumber(5, 5, 5, 0, 100)).toBe(50);
36	  });
37	  it("handles inverted range", () => {
38	    expect(scaleNumber(0, 0, 100, 200, 0)).toBe(200);
39	  });
40	  it("extrapolates beyond domain", () => {
41	    expect(scaleNumber(200, 0, 100, 0, 100)).toBe(200);
42	  });
43	});
44	
45	describe("buildLinePath", () => {
46	  it("returns empty string for empty array", () => {
47	    expect(buildLinePath([])).toBe("");
