1	import type {
2	  AnalyticsInterval,
3	  MarketAnalyticsVolumeBucket,
4	} from "@/lib/api/types";
5	import { formatCurrency } from "@/lib/utils/format";
6	import { formatBucketRangeLabel, scaleNumber } from "./chartUtils";
7	
8	interface VolumeChartProps {
9	  buckets: MarketAnalyticsVolumeBucket[];
10	  interval: AnalyticsInterval;
11	}
12	
13	const WIDTH = 760;
14	const HEIGHT = 280;
15	const MARGIN = { top: 24, right: 24, bottom: 54, left: 52 };
16	
17	export function VolumeChart({ buckets, interval }: VolumeChartProps) {
18	  const values = buckets.map((bucket) => bucket.volume);
19	  const maxVolume = values.length > 0 ? Math.max(...values) : 1;
20	  const innerWidth = WIDTH - MARGIN.left - MARGIN.right;
21	  const chartBottom = HEIGHT - MARGIN.bottom;
22	  const chartTop = MARGIN.top;
23	  const labelEvery = Math.max(1, Math.ceil(buckets.length / 5));
24	  const barWidth = Math.min(
25	    88,
26	    Math.max(30, innerWidth / Math.max(buckets.length * 1.4, 1)),
27	  );
28	  const midpoints = buckets.map((bucket) => {
29	    const start = Date.parse(bucket.bucketStart);
30	    const end = Date.parse(bucket.bucketEnd);
31	    return start + (end - start) / 2;
32	  });
33	  const domainStart = midpoints.length > 0 ? Math.min(...midpoints) : Date.now();
34	  const domainEnd = midpoints.length > 1 ? Math.max(...midpoints) : domainStart + 1;
35	
36	  return (
37	    <section style={cardStyle}>
38	      <div style={headerStyle}>
39	        <div>
40	          <h2 style={titleStyle}>Activity Volume</h2>
41	          <p style={subtitleStyle}>
42	            Accepted trade and edit volume grouped into sparse UTC buckets.
43	          </p>
44	        </div>
45	      </div>
46	
47	      <div style={{ overflowX: "auto" }}>
48	        <svg
49	          data-testid="volume-chart"
50	          role="img"
51	          aria-label="Activity volume chart"
52	          viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
53	          style={{ width: "100%", height: "auto", minWidth: 460 }}
54	        >
55	          {[0, 0.5, 1].map((ratio) => {
56	            const y = scaleNumber(ratio, 0, 1, chartBottom, chartTop);
57	            const value = maxVolume * ratio;
58	            return (
59	              <g key={ratio}>
60	                <line
61	                  x1={MARGIN.left}
62	                  y1={y}
63	                  x2={WIDTH - MARGIN.right}
64	                  y2={y}
65	                  stroke="rgba(139, 143, 163, 0.28)"
66	                  strokeDasharray="4 4"
67	                />
68	                <text
69	                  x={MARGIN.left - 10}
70	                  y={y + 4}
71	                  fill="var(--color-text-muted)"
72	                  fontSize="11"
73	                  textAnchor="end"
74	                >
75	                  {formatCurrency(value)}
76	                </text>
77	              </g>
78	            );
79	          })}
80	
81	          <line
82	            x1={MARGIN.left}
83	            y1={chartBottom}
84	            x2={WIDTH - MARGIN.right}
85	            y2={chartBottom}
86	            stroke="var(--color-border)"
87	          />
88	          <line
89	            x1={MARGIN.left}
90	            y1={chartTop}
91	            x2={MARGIN.left}
92	            y2={chartBottom}
93	            stroke="var(--color-border)"
94	          />
95	
96	          {buckets.map((bucket, index) => {
97	            const midpoint = midpoints[index] ?? domainStart;
98	            const xCenter =
99	              buckets.length === 1
100	                ? MARGIN.left + innerWidth / 2
101	                : scaleNumber(
102	                    midpoint,
103	                    domainStart,
104	                    domainEnd,
105	                    MARGIN.left + barWidth / 2,
106	                    WIDTH - MARGIN.right - barWidth / 2,
107	                  );
108	            const barHeight = scaleNumber(
109	              bucket.volume,
110	              0,
111	              maxVolume || 1,
112	              0,
113	              chartBottom - chartTop,
114	            );
115	            const x = xCenter - barWidth / 2;
116	            const y = chartBottom - barHeight;
117	            const showLabel = index % labelEvery === 0;
118	
119	            return (
120	              <g key={`${bucket.bucketStart}-${bucket.bucketEnd}`}>
121	                <rect
122	                  x={x}
123	                  y={y}
124	                  width={barWidth}
125	                  height={barHeight}
126	                  rx="8"
127	                  fill="rgba(99, 102, 241, 0.75)"
128	                />
129	                <text
130	                  x={xCenter}
131	                  y={y - 8}
132	                  fill="var(--color-text)"
133	                  fontSize="11"
134	                  textAnchor="middle"
135	                >
136	                  {bucket.tradeCount}
137	                </text>
138	                {showLabel && (
139	                  <text
140	                    x={xCenter}
141	                    y={HEIGHT - 20}
142	                    fill="var(--color-text-muted)"
143	                    fontSize="11"
144	                    textAnchor="middle"
145	                  >
146	                    {formatBucketRangeLabel(
147	                      bucket.bucketStart,
148	                      bucket.bucketEnd,
149	                      interval,
150	                    )}
151	                  </text>
152	                )}
153	              </g>
154	            );
155	          })}
156	        </svg>
157	      </div>
158	    </section>
159	  );
160	}
